        let driftedLMStudioRequests = LockedBox<[ChatRequest]>([])
        let driftedLMStudioModel = ModelInfo(
            id: "shared-summary-alias",
            name: "shared-summary-alias",
            provider: .lmStudio,
            providerModelID: "lmstudio-summary-current",
            installed: true
        )
