            documentStore.sourceAuditEvents(limit: 100)
                .filter { $0.action == .trustedSourceContextConsumed }.count,
            consumedBefore
        )
        XCTAssertEqual(
            try notebookStore.get(ownerDeviceID: ownerDeviceID, notebookID: notebook.notebookID),
            notebook
        )
    }

