        XCTAssertEqual(duplicate?.type, MessageType.error)
        XCTAssertEqual(
            duplicate?.payload["code"],
            .string("relay_allocation_authorization_rejected")
        )
        XCTAssertEqual(harness.refresher.clientProofs, [])
    }

