        ), sink: sinkB)
        let messagesBA = try await sinkB.waitForMessages(count: 7).last
        XCTAssertEqual(messagesBA?.payload["messages"], .array([]))

        router.handle(ProtocolEnvelope(
            type: MessageType.chatSessionRename,
