        let router = LocalRuntimeMessageRouter(
            backend: MockBackend(status: .available, models: [
                ModelInfo(id: "llama3.1:8b", name: "Llama 3.1", sizeBytes: nil, modifiedAt: nil)
            ]),
            trustedDeviceStore: store
        )
