        XCTAssertEqual(relayClient.startedConfiguration?.host, "relay.bootstrap.test")
        XCTAssertEqual(relayClient.startedConfiguration?.port, 443)
        XCTAssertEqual(relayClient.startedConfiguration?.relayID, "relay-renewed")
