private func waitForPendingModelPullReview(
    _ broker: RuntimeModelPullApprovalBroker,
    timeout: TimeInterval = 1
) async throws -> CompanionPendingModelPullReview {
    let deadline = Date().addingTimeInterval(timeout)
    while Date() < deadline {
        if let review = await broker.pendingReviews().first {
            return review
        }
        try await Task.sleep(nanoseconds: 10_000_000)
    }
    throw NSError(
        domain: "RuntimeModelPullApprovalRouterTests",
        code: 1,
        userInfo: [NSLocalizedDescriptionKey: "Timed out waiting for a pending model-pull review"]
    )
}

private func researchBriefCreateEnvelope(
    requestID: String,
    notebookID: String,
    sessionID: String,
    topic: String,
    grantIDs: [String],
    locale: String? = nil
) -> ProtocolEnvelope {
    var payload: [String: JSONValue] = [
        "notebook_id": .string(notebookID),
        "session_id": .string(sessionID),
        "topic": .string(topic),
        "model": .string("llama3.1:8b"),
        "trusted_source_grant_ids": .array(grantIDs.map(JSONValue.string)),
    ]
    if let locale {
        payload["locale"] = .string(locale)
    }
    return ProtocolEnvelope(
        type: MessageType.researchBriefCreate,
        requestID: requestID,
        payload: payload
    )
}

