private actor BlockingTrustedDeviceLookup {
    private let device: TrustedDevice
    private var shouldBlockNextLookup = false
    private var blockedLookupContinuation: CheckedContinuation<Void, Never>?

    init(device: TrustedDevice) {
        self.device = device
    }

    func blockNextLookup() {
        shouldBlockNextLookup = true
    }

    func lookup(deviceID: String) async -> TrustedDevice? {
        if shouldBlockNextLookup {
            shouldBlockNextLookup = false
            await withCheckedContinuation { continuation in
                blockedLookupContinuation = continuation
            }
        }
        return device.id == deviceID ? device : nil
    }

    func waitUntilBlocked() async -> Bool {
        for _ in 0..<500 {
            if blockedLookupContinuation != nil { return true }
            try? await Task.sleep(nanoseconds: 1_000_000)
        }
        return false
    }

    func releaseBlockedLookup() {
        let continuation = blockedLookupContinuation
        blockedLookupContinuation = nil
        continuation?.resume()
    }
}

private actor AsyncTestGate {
    private var isOpen = false
    private var waiters: [CheckedContinuation<Void, Never>] = []

    func wait() async {
        guard !isOpen else { return }
        await withCheckedContinuation { continuation in
            waiters.append(continuation)
        }
    }

    func open() {
        guard !isOpen else { return }
        isOpen = true
        let currentWaiters = waiters
        waiters.removeAll()
        currentWaiters.forEach { $0.resume() }
    }
}

private actor OneShotAsyncCheckpoint {
    private var entered = false
    private var continuation: CheckedContinuation<Void, Never>?

    func waitIfFirst() async {
        guard !entered else { return }
        entered = true
        await withCheckedContinuation { continuation in
            self.continuation = continuation
        }
    }

    func waitUntilEntered() async -> Bool {
        for _ in 0..<500 {
            if entered { return true }
            try? await Task.sleep(nanoseconds: 1_000_000)
        }
        return false
    }

    func release() {
        let continuation = continuation
        self.continuation = nil
        continuation?.resume()
    }
}

private final class ManualChatTitleGenerationDeadlineScheduler: @unchecked Sendable {
    private struct Entry {
        var id: UUID
        var action: @Sendable () -> Void
    }

    private let lock = NSLock()
    private var entries: [Entry] = []
    private var storedScheduledCount = 0

    var scheduledCount: Int {
        lock.withLock { storedScheduledCount }
    }

    func schedule(
        _ nanoseconds: UInt64,
        action: @escaping @Sendable () -> Void
    ) -> (@Sendable () -> Void) {
        _ = nanoseconds
        let id = UUID()
        lock.withLock {
            storedScheduledCount += 1
            entries.append(Entry(id: id, action: action))
        }
        return { [weak self] in
            self?.cancel(id)
        }
    }

    func fireNext() -> Bool {
        let action = lock.withLock { () -> (@Sendable () -> Void)? in
            guard !entries.isEmpty else { return nil }
            return entries.removeFirst().action
        }
        action?()
        return action != nil
    }

    private func cancel(_ id: UUID) {
        lock.withLock {
            entries.removeAll { $0.id == id }
        }
    }
}

