private func clientAuthenticationSignature(
    privateKey: P256.Signing.PrivateKey,
    deviceID: String,
    nonce: String,
    transportBinding: String? = nil
) throws -> String {
    let message = LocalRuntimeMessageRouter.clientAuthenticationResponseMessage(
        deviceID: deviceID,
        nonce: nonce,
        transportBinding: transportBinding
    )
    let messageData = try XCTUnwrap(message.data(using: .utf8))
    return try privateKey
        .signature(for: SHA256.hash(data: messageData))
        .derRepresentation
        .base64EncodedString()
}

private func reauthenticateTrustedDevice(
    router: LocalRuntimeMessageRouter,
    sink: RecordingSink,
    deviceID: String,
    privateKey: P256.Signing.PrivateKey,
    clientCapabilities: [String],
    existingMessageCount: Int,
    requestSuffix: String
) async throws {
    var helloPayload: [String: JSONValue] = ["device_id": .string(deviceID)]
    if !clientCapabilities.isEmpty {
        helloPayload["client_capabilities"] = .array(clientCapabilities.map(JSONValue.string))
    }
    router.handle(ProtocolEnvelope(
        type: MessageType.hello,
        requestID: "hello-\(requestSuffix)",
        payload: helloPayload
    ), sink: sink)
    let challenge = try await sink.waitForMessages(count: existingMessageCount + 1).last
    guard case .string(let nonce)? = challenge?.payload["nonce"] else {
        XCTFail("Expected nonce in reauthentication challenge")
        return
    }
    router.handle(ProtocolEnvelope(
        type: MessageType.authResponse,
        requestID: "auth-\(requestSuffix)",
        payload: [
            "device_id": .string(deviceID),
            "nonce": .string(nonce),
            "signature": .string(try clientAuthenticationSignature(
                privateKey: privateKey,
                deviceID: deviceID,
                nonce: nonce
            ))
        ]
    ), sink: sink)
    let response = try await sink.waitForMessages(count: existingMessageCount + 2).last
    XCTAssertEqual(response?.type, MessageType.authResponse)
    XCTAssertEqual(response?.payload["accepted"], .bool(true))
}

private func authenticateTrustedDevice(
    router: LocalRuntimeMessageRouter,
    sink: RecordingSink,
    deviceID: String,
    privateKey: P256.Signing.PrivateKey,
    transportBinding: String? = nil,
    clientCapabilities: [String] = []
) async throws {
    try await authenticateTrustedDevice(
        send: { envelope, sink in router.handle(envelope, sink: sink) },
        sink: sink,
        deviceID: deviceID,
        privateKey: privateKey,
        transportBinding: transportBinding,
        clientCapabilities: clientCapabilities
    )
}

private func authenticateTrustedDevice(
    handler: LocalPeerMessageHandler,
    sink: RecordingSink,
    deviceID: String,
    privateKey: P256.Signing.PrivateKey,
    transportBinding: String? = nil,
    clientCapabilities: [String] = []
) async throws {
    try await authenticateTrustedDevice(
        send: handler,
        sink: sink,
        deviceID: deviceID,
        privateKey: privateKey,
        transportBinding: transportBinding,
        clientCapabilities: clientCapabilities
    )
}

private func authenticateTrustedDevice(
    send: (ProtocolEnvelope, any RuntimeMessageSink) -> Void,
    sink: RecordingSink,
    deviceID: String,
    privateKey: P256.Signing.PrivateKey,
    transportBinding: String? = nil,
    clientCapabilities: [String] = []
) async throws {
    var helloPayload: [String: JSONValue] = ["device_id": .string(deviceID)]
    if let transportBinding {
        helloPayload["transport_binding"] = .string(transportBinding)
    }
    if !clientCapabilities.isEmpty {
        helloPayload["client_capabilities"] = .array(clientCapabilities.map(JSONValue.string))
    }
    send(ProtocolEnvelope(
        type: MessageType.hello,
        requestID: "hello-\(deviceID)",
        payload: helloPayload
    ), sink)

    let challenge = try await sink.waitForMessages(count: 1).last
    XCTAssertEqual(challenge?.type, MessageType.authChallenge)
    guard case .string(let nonce)? = challenge?.payload["nonce"] else {
        XCTFail("Expected nonce in auth challenge")
        return
    }
    let authMessage = LocalRuntimeMessageRouter.clientAuthenticationResponseMessage(
        deviceID: deviceID,
        nonce: nonce,
        transportBinding: transportBinding
    )
    let authMessageData = try XCTUnwrap(authMessage.data(using: .utf8))
    let signature = try privateKey
        .signature(for: SHA256.hash(data: authMessageData))
        .derRepresentation
        .base64EncodedString()
    var authPayload: [String: JSONValue] = [
        "device_id": .string(deviceID),
        "nonce": .string(nonce),
        "signature": .string(signature)
    ]
    if let transportBinding {
        authPayload["transport_binding"] = .string(transportBinding)
    }
    send(ProtocolEnvelope(
        type: MessageType.authResponse,
        requestID: "auth-\(deviceID)",
        payload: authPayload
    ), sink)

    let authResponse = try await sink.waitForMessages(count: 2).last
    XCTAssertEqual(authResponse?.type, MessageType.authResponse)
    XCTAssertEqual(authResponse?.payload["accepted"], .bool(true))
}

private func chatSendEnvelope(requestID: String, sessionID: String, content: String) -> ProtocolEnvelope {
