private struct TestRuntimeChallengeSigner: RuntimeChallengeSigning, RelayIdentityAuthorizationSigning, InitialPairingRuntimeResultSigning {
    var privateKey: P256.Signing.PrivateKey

    func relayRuntimeIdentity() throws -> RelayRuntimeIdentity {
        let identity = RuntimeIdentityKeyStore.identityKey(from: privateKey)
        return try RelayRuntimeIdentity(
            publicKeyBase64: identity.publicKeyBase64,
            fingerprint: identity.fingerprint
        )
    }

    func signRelayAllocationChallenge(
        _ challenge: RelayAllocationIdentityChallenge
    ) throws -> RelayIdentityAuthorizationProof {
        try relayIdentityProof(messageData: challenge.signedMessageData())
    }

    func signRelayRuntimeRegistrationChallenge(
        _ challenge: RelayRuntimeRegistrationIdentityChallenge
    ) throws -> RelayIdentityAuthorizationProof {
        try relayIdentityProof(messageData: challenge.signedMessageData())
    }

    func signAuthChallenge(
        deviceID: String,
        nonce: String,
        transportBinding: String?
    ) throws -> RuntimeChallengeSignature {
        let identity = RuntimeIdentityKeyStore.identityKey(from: privateKey)
        let messageData = RuntimeIdentityKeyStore.authChallengeMessageData(
            deviceID: deviceID,
            nonce: nonce,
            transportBinding: transportBinding
        )
        let signature = try privateKey.signature(for: SHA256.hash(data: messageData))
        return RuntimeChallengeSignature(
            runtimeKeyFingerprint: identity.fingerprint,
            signatureBase64: signature.derRepresentation.base64EncodedString()
        )
    }

    func signInitialPairingResult(
        _ result: InitialPairingRuntimeResult
    ) throws -> InitialPairingRuntimeResultProof {
        let identity = RuntimeIdentityKeyStore.identityKey(from: privateKey)
        guard result.runtimePublicKey == identity.publicKeyBase64,
              result.runtimeKeyFingerprint == identity.fingerprint else {
            throw InitialPairingProofError.invalidPublicKey("runtime_public_key")
        }
        let signature = try privateKey.signature(
            for: SHA256.hash(data: result.signedMessageData())
        )
        return try InitialPairingRuntimeResultProof(
            result: result,
            signatureBase64: signature.derRepresentation.base64EncodedString()
        )
    }

    private func relayIdentityProof(messageData: Data) throws -> RelayIdentityAuthorizationProof {
        let signature = try privateKey.signature(for: SHA256.hash(data: messageData))
        return try RelayIdentityAuthorizationProof(
            runtimeIdentity: relayRuntimeIdentity(),
            signatureBase64: signature.derRepresentation.base64EncodedString()
        )
    }
}

private func testRelayAuthorization() throws -> (
    identity: RelayRuntimeIdentity,
    signer: TestRuntimeChallengeSigner
) {
    let signer = TestRuntimeChallengeSigner(privateKey: P256.Signing.PrivateKey())
    return (try signer.relayRuntimeIdentity(), signer)
}

private func testRelayAllocationChallenge(
    routeToken: String,
    runtimeIdentity: RelayRuntimeIdentity,
    ticketGeneration: Int64 = 1
) throws -> RelayAllocationIdentityChallenge {
    try RelayAllocationIdentityChallenge(
        operation: ticketGeneration == 1 ? .create : .renew,
        relayID: RelayAllocationIdentityChallenge.relayID(
            routeToken: routeToken,
            runtimeKeyFingerprint: runtimeIdentity.fingerprint
        ),
        routeTokenHash: RelayAllocationIdentityChallenge.routeTokenHash(routeToken),
        runtimeKeyFingerprint: runtimeIdentity.fingerprint,
        ticketGeneration: ticketGeneration,
        challenge: String(repeating: "a", count: 64),
        challengeExpiresAtEpochMillis: 4_102_444_800_000
    )
}

private extension EnvironmentRemoteRelayRouteAllocator {
    func allocateRemoteRelayRoute(
        runtimeDeviceID: String,
        routeToken: String,
        preferredRelaySecret: String?
    ) throws -> CompanionRemoteRelayRouteAllocation? {
        let authorization = try testRelayAuthorization()
        return try allocateRemoteRelayRoute(
            runtimeDeviceID: runtimeDeviceID,
            routeToken: routeToken,
            preferredRelaySecret: preferredRelaySecret,
            runtimeIdentity: authorization.identity,
            identityAuthorizationSigner: authorization.signer
        )
    }
}

private struct RecordingRuntimeMemoryListRequest: Equatable {
    var ownerDeviceID: String?
}

private struct RecordingRuntimeMemoryUpsertRequest: Equatable {
    var ownerDeviceID: String?
    var id: String?
    var content: String
    var enabled: Bool?
}

private struct RecordingRuntimeMemoryDeleteRequest: Equatable {
    var ownerDeviceID: String?
    var id: String
}

private struct RecordingRuntimeMemorySummaryDraftDismissRequest: Equatable {
    var ownerDeviceID: String?
    var draftID: String
}

private final class RecordingRuntimeMemoryStore: RuntimeMemoryStore, @unchecked Sendable {
    private let lock = NSLock()
    private var entries: [RuntimeMemoryEntry]
    private var recordedListRequests: [RecordingRuntimeMemoryListRequest] = []
    private var recordedUpsertRequests: [RecordingRuntimeMemoryUpsertRequest] = []
    private var recordedDeleteRequests: [RecordingRuntimeMemoryDeleteRequest] = []
    private var recordedDismissMemorySummaryDraftRequests: [RecordingRuntimeMemorySummaryDraftDismissRequest] = []

    init(entries: [RuntimeMemoryEntry] = []) {
        self.entries = entries
    }

    var listRequests: [RecordingRuntimeMemoryListRequest] {
        lock.withLock { recordedListRequests }
    }

    var upsertRequests: [RecordingRuntimeMemoryUpsertRequest] {
        lock.withLock { recordedUpsertRequests }
    }

    var deleteRequests: [RecordingRuntimeMemoryDeleteRequest] {
        lock.withLock { recordedDeleteRequests }
    }

    var dismissMemorySummaryDraftRequests: [RecordingRuntimeMemorySummaryDraftDismissRequest] {
        lock.withLock { recordedDismissMemorySummaryDraftRequests }
    }

    func list(ownerDeviceID: String?) throws -> [RuntimeMemoryEntry] {
        lock.withLock {
            recordedListRequests.append(RecordingRuntimeMemoryListRequest(ownerDeviceID: ownerDeviceID))
            return entries
        }
    }

    func listAll() throws -> [RuntimeMemoryEntry] {
        try list(ownerDeviceID: nil)
    }

    func upsert(
        ownerDeviceID: String?,
        id: String?,
        content: String,
        enabled: Bool?,
        source: RuntimeMemoryEntrySource?,
        timestamp: Date
    ) throws -> RuntimeMemoryEntry {
        let entry = RuntimeMemoryEntry(
            id: id ?? UUID().uuidString,
            content: content.trimmingCharacters(in: .whitespacesAndNewlines),
            enabled: enabled ?? true,
            createdAt: timestamp,
            updatedAt: timestamp,
            source: source
        )
        lock.withLock {
            recordedUpsertRequests.append(RecordingRuntimeMemoryUpsertRequest(
                ownerDeviceID: ownerDeviceID,
                id: id,
                content: content,
                enabled: enabled
            ))
            entries.removeAll { $0.id == entry.id }
            entries.append(entry)
        }
        return entry
    }

    func approveMemorySummaryDraft(
        ownerDeviceID: String?,
        draftID: String,
        id: String,
        content: String,
        enabled: Bool,
        source: RuntimeMemoryEntrySource,
        timestamp: Date
    ) throws -> RuntimeMemoryEntry {
        try upsert(
            ownerDeviceID: ownerDeviceID,
            id: id,
            content: content,
            enabled: enabled,
            source: source,
            timestamp: timestamp
        )
    }

    func delete(ownerDeviceID: String?, id: String, timestamp: Date) throws -> RuntimeMemoryDeleteResult {
        lock.withLock {
            recordedDeleteRequests.append(RecordingRuntimeMemoryDeleteRequest(
                ownerDeviceID: ownerDeviceID,
                id: id
            ))
            entries.removeAll { $0.id == id }
        }
        return RuntimeMemoryDeleteResult(id: id, deletedAt: timestamp)
    }

    func dismissedMemorySummaryDraftIDs(ownerDeviceID: String?) throws -> Set<String> {
        []
    }

    func dismissMemorySummaryDraft(
        ownerDeviceID: String?,
        draftID: String,
        timestamp: Date
    ) throws -> RuntimeMemorySummaryDraftDismissResult {
        lock.withLock {
            recordedDismissMemorySummaryDraftRequests.append(RecordingRuntimeMemorySummaryDraftDismissRequest(
                ownerDeviceID: ownerDeviceID,
                draftID: draftID
            ))
        }
        return RuntimeMemorySummaryDraftDismissResult(draftID: draftID, dismissedAt: timestamp)
    }
}

private final class BlockingMemorySummaryDecisionStore: RuntimeMemoryStore, @unchecked Sendable {
    enum Operation: String, CaseIterable, Sendable {
        case approve
        case dismiss
    }

    let mutationEntered = DispatchSemaphore(value: 0)
    let releaseMutation = DispatchSemaphore(value: 0)
    private let operation: Operation

    init(operation: Operation) {
        self.operation = operation
    }

    func list(ownerDeviceID: String?) throws -> [RuntimeMemoryEntry] { [] }

    func listAll() throws -> [RuntimeMemoryEntry] { [] }

    func upsert(
        ownerDeviceID: String?,
        id: String?,
        content: String,
        enabled: Bool?,
        source: RuntimeMemoryEntrySource?,
        timestamp: Date
    ) throws -> RuntimeMemoryEntry {
        guard operation == .approve else {
            throw NSError(domain: "AetherLinkTests.UnexpectedDecision", code: 1)
        }
        mutationEntered.signal()
        releaseMutation.wait()
        return RuntimeMemoryEntry(
            id: id ?? UUID().uuidString,
            content: content,
            enabled: enabled ?? true,
            createdAt: timestamp,
            updatedAt: timestamp,
            source: source
        )
    }

    func approveMemorySummaryDraft(
        ownerDeviceID: String?,
        draftID: String,
        id: String,
        content: String,
        enabled: Bool,
        source: RuntimeMemoryEntrySource,
        timestamp: Date
    ) throws -> RuntimeMemoryEntry {
        try upsert(
            ownerDeviceID: ownerDeviceID,
            id: id,
            content: content,
            enabled: enabled,
            source: source,
            timestamp: timestamp
        )
    }

    func delete(
        ownerDeviceID: String?,
        id: String,
        timestamp: Date
    ) throws -> RuntimeMemoryDeleteResult {
        throw NSError(domain: "AetherLinkTests.UnexpectedDecision", code: 2)
    }

    func dismissedMemorySummaryDraftIDs(ownerDeviceID: String?) throws -> Set<String> { [] }

    func dismissMemorySummaryDraft(
        ownerDeviceID: String?,
        draftID: String,
        timestamp: Date
    ) throws -> RuntimeMemorySummaryDraftDismissResult {
        guard operation == .dismiss else {
            throw NSError(domain: "AetherLinkTests.UnexpectedDecision", code: 3)
        }
        mutationEntered.signal()
        releaseMutation.wait()
        return RuntimeMemorySummaryDraftDismissResult(draftID: draftID, dismissedAt: timestamp)
    }
}

