    private var modelListCancellations = 0
    private let chatEvents: [ChatStreamEvent]
    private let chatEventBatchesLock = NSLock()
    private var chatEventBatches: [[ChatStreamEvent]]
    private var chatProviderUsageSources: [ChatProviderUsageSource?]
    private var completedProviderUsageSources: [String: ChatProviderUsageSource] = [:]
    private var chatStreamFinishBatches: [Bool]
    private let chatContinuationsLock = NSLock()
    private var chatContinuations: [AsyncThrowingStream<ChatStreamEvent, Error>.Continuation] = []
    private let cancelledGenerationIDsLock = NSLock()
    private var cancelledIDs: [String] = []
    private let pulledModelNamesLock = NSLock()
    private var pulledNames: [String] = []
    private let finishChatStream: Bool
    private let cancelFinishesChatStream: Bool
    private let cancelResult: GenerationCancellationResult
    private let cancelHandler: ((String) -> GenerationCancellationResult)?
    private let onListModels: (() -> Void)?
    private let onChatRequest: ((ChatRequest) -> Void)?
    private let onChatStreamReady: (() -> Void)?

    init(
        provider: ModelProvider = .ollama,
        status: BackendStatus = .available,
        models: [ModelInfo] = [],
        modelListBatches: [[ModelInfo]] = [],
        modelListResultBatches: [Result<[ModelInfo], Error>] = [],
        modelListError: Error? = nil,
        holdModelListUntilReleased: Bool = false,
        holdModelListUntilCancelled: Bool = false,
        holdModelListCancellationUntilReleased: Bool = false,
        pullResult: ModelPullResult = ModelPullResult(model: "mock", status: "success", installed: true),
        pullError: Error? = nil,
        unloadError: Error? = nil,
        embeddingResult: EmbeddingResult? = nil,
        embeddingError: Error? = nil,
        embeddingResultBatches: [Result<EmbeddingResult, Error>] = [],
        holdEmbeddingUntilCancelled: Bool = false,
        holdEmbeddingUntilReleased: Bool = false,
        ignoreEmbeddingCancellationAfterRelease: Bool = false,
        chatEvents: [ChatStreamEvent] = [],
        chatEventBatches: [[ChatStreamEvent]] = [],
        chatStreamFinishBatches: [Bool] = [],
        chatProviderUsageSources: [ChatProviderUsageSource?] = [],
        finishChatStream: Bool = true,
        cancelFinishesChatStream: Bool = false,
        cancelResult: GenerationCancellationResult = .notFound(generationID: "missing"),
        onListModels: (() -> Void)? = nil,
        onChatRequest: ((ChatRequest) -> Void)? = nil,
        onChatStreamReady: (() -> Void)? = nil,
        cancelHandler: ((String) -> GenerationCancellationResult)? = nil
    ) {
        self.provider = provider
        self.status = status
        self.models = models
        self.modelListBatches = modelListBatches
        self.modelListResultBatches = modelListResultBatches
        self.modelListError = modelListError
        self.holdModelListUntilReleased = holdModelListUntilReleased
        self.holdModelListUntilCancelled = holdModelListUntilCancelled
        self.holdModelListCancellationUntilReleased =
            holdModelListCancellationUntilReleased
        self.pullResult = pullResult
        self.pullError = pullError
        self.unloadError = unloadError
        self.embeddingResult = embeddingResult
        self.embeddingError = embeddingError
        self.embeddingResultBatches = embeddingResultBatches
        self.holdEmbeddingUntilCancelled = holdEmbeddingUntilCancelled
        self.holdEmbeddingUntilReleased = holdEmbeddingUntilReleased
        self.ignoreEmbeddingCancellationAfterRelease = ignoreEmbeddingCancellationAfterRelease
        self.chatEvents = chatEvents
        self.chatEventBatches = chatEventBatches
        self.chatStreamFinishBatches = chatStreamFinishBatches
        self.chatProviderUsageSources = chatProviderUsageSources
        self.finishChatStream = finishChatStream
        self.cancelFinishesChatStream = cancelFinishesChatStream
        self.cancelResult = cancelResult
        self.cancelHandler = cancelHandler
        self.onListModels = onListModels
        self.onChatRequest = onChatRequest
        self.onChatStreamReady = onChatStreamReady
    }

    var cancelledGenerationIDs: [String] {
        cancelledGenerationIDsLock.withLock { cancelledIDs }
    }

    var pulledModelNames: [String] {
        pulledModelNamesLock.withLock { pulledNames }
    }

    var healthCheckCallCount: Int {
        healthCheckCallCountLock.withLock { healthCheckCalls }
    }

    var listModelsCallCount: Int {
        listModelsCallCountLock.withLock { listModelsCalls }
    }

    var modelListCancellationCount: Int {
        modelListCancellationCountLock.withLock { modelListCancellations }
    }

    var embeddingRequests: [EmbeddingRequest] {
        embeddingRequestsLock.withLock { recordedEmbeddingRequests }
    }

    var embeddingCancellationCount: Int {
        embeddingCancellationCountLock.withLock { embeddingCancellations }
    }

    func releaseHeldEmbeddings() {
        let continuations = embeddingReleaseLock.withLock {
            let continuations = embeddingReleaseContinuations
            embeddingReleaseContinuations.removeAll()
            return continuations
        }
        continuations.forEach { $0.resume() }
    }

    func releaseHeldModelLists() {
        let continuations = modelListReleaseLock.withLock {
            modelListReleaseRequested = true
            let continuations = modelListReleaseContinuations
            modelListReleaseContinuations.removeAll()
            return continuations
        }
        continuations.forEach { $0.resume() }
    }

    func releaseHeldModelListCancellation() {
        let continuations = modelListCancellationReleaseLock.withLock {
            modelListCancellationReleaseRequested = true
            let continuations = modelListCancellationReleaseContinuations
            modelListCancellationReleaseContinuations.removeAll()
            return continuations
        }
        continuations.forEach { $0.resume() }
    }

    func finishChat(with events: [ChatStreamEvent]) {
        let continuations = chatContinuationsLock.withLock {
            let continuations = chatContinuations
            chatContinuations.removeAll()
            return continuations
        }
        continuations.forEach { continuation in
            events.forEach { continuation.yield($0) }
            continuation.finish()
        }
    }

    func failChat(with error: Error) {
        let continuations = chatContinuationsLock.withLock {
            let continuations = chatContinuations
            chatContinuations.removeAll()
            return continuations
        }
        continuations.forEach { $0.finish(throwing: error) }
    }

    func healthCheck() async -> BackendStatus {
        healthCheckCallCountLock.withLock {
            healthCheckCalls += 1
        }
        return status
    }

    func listModels() async throws -> [ModelInfo] {
        let (result, callOrdinal) = listModelsCallCountLock.withLock {
            () -> (Result<[ModelInfo], Error>, Int) in
            listModelsCalls += 1
            let callOrdinal = listModelsCalls
            if !modelListResultBatches.isEmpty {
                return (modelListResultBatches.removeFirst(), callOrdinal)
            }
            let nextModels = modelListBatches.isEmpty ? models : modelListBatches.removeFirst()
            if let modelListError {
                return (.failure(modelListError), callOrdinal)
            }
            return (.success(nextModels), callOrdinal)
        }
        onListModels?()
        if holdModelListUntilReleased {
            await withCheckedContinuation { continuation in
                let resumeImmediately = modelListReleaseLock.withLock { () -> Bool in
                    guard !modelListReleaseRequested else { return true }
                    modelListReleaseContinuations.append(continuation)
                    return false
                }
                if resumeImmediately { continuation.resume() }
            }
        }
        if holdModelListUntilCancelled && callOrdinal == 1 {
            do {
                try await Task.sleep(nanoseconds: UInt64.max)
            } catch {
                modelListCancellationCountLock.withLock {
                    modelListCancellations += 1
                }
                if holdModelListCancellationUntilReleased {
                    await withCheckedContinuation { continuation in
                        let resumeImmediately = modelListCancellationReleaseLock.withLock {
                            () -> Bool in
                            guard !modelListCancellationReleaseRequested else { return true }
                            modelListCancellationReleaseContinuations.append(continuation)
                            return false
                        }
                        if resumeImmediately { continuation.resume() }
                    }
                }
                throw error
            }
        }
        return try result.get()
    }

    func pullModel(name: String) async throws -> ModelPullResult {
        pulledModelNamesLock.withLock {
            pulledNames.append(name)
        }
        if let pullError {
            throw pullError
        }
        return ModelPullResult(model: name, status: pullResult.status, installed: pullResult.installed)
    }

    func chat(request: ChatRequest) -> AsyncThrowingStream<ChatStreamEvent, Error> {
        AsyncThrowingStream { continuation in
            onChatRequest?(request)
            let batch = nextChatBatch()
            if batch.events.contains(where: { if case .done = $0 { true } else { false } }),
               let source = batch.providerUsageSource {
                chatEventBatchesLock.withLock {
                    completedProviderUsageSources[request.generationID] = source
                }
            }
            batch.events.forEach { continuation.yield($0) }
            if batch.shouldFinishStream {
                continuation.finish()
            } else {
                chatContinuationsLock.withLock {
                    chatContinuations.append(continuation)
                }
            }
            onChatStreamReady?()
        }
    }

    func takeProviderUsageSource(generationID: String) -> ChatProviderUsageSource? {
        chatEventBatchesLock.withLock {
            completedProviderUsageSources.removeValue(forKey: generationID)
        }
    }

    func embed(request: EmbeddingRequest) async throws -> EmbeddingResult {
        let batchedResult = embeddingRequestsLock.withLock {
            recordedEmbeddingRequests.append(request)
            return embeddingResultBatches.isEmpty ? nil : embeddingResultBatches.removeFirst()
        }
        if let batchedResult {
            return try batchedResult.get()
        }
        if let embeddingError {
            throw embeddingError
        }
        if holdEmbeddingUntilReleased {
            await withCheckedContinuation { continuation in
                embeddingReleaseLock.withLock {
                    embeddingReleaseContinuations.append(continuation)
                }
            }
            if Task.isCancelled {
                embeddingCancellationCountLock.withLock {
                    embeddingCancellations += 1
                }
                if !ignoreEmbeddingCancellationAfterRelease {
                    try Task.checkCancellation()
                }
            }
        }
        if holdEmbeddingUntilCancelled {
            do {
                try await Task.sleep(nanoseconds: UInt64.max)
            } catch {
                embeddingCancellationCountLock.withLock {
                    embeddingCancellations += 1
                }
                throw error
            }
        }
        return embeddingResult ?? EmbeddingResult(
            model: request.model,
            embeddings: request.texts.map(Self.deterministicEmbedding)
        )
    }

    func unloadModel(providerModelID: String) async throws -> ModelUnloadResult {
        if let unloadError {
            throw unloadError
        }
        return .unsupported(provider: provider, modelID: providerModelID)
    }

    func cancel(generationID: String) -> GenerationCancellationResult {
        cancelledGenerationIDsLock.withLock {
            cancelledIDs.append(generationID)
        }
        if let cancelHandler {
            return cancelHandler(generationID)
        }
        if cancelFinishesChatStream {
            let continuations = chatContinuationsLock.withLock {
                let continuations = chatContinuations
                chatContinuations.removeAll()
                return continuations
            }
            continuations.forEach { continuation in
                continuation.finish(throwing: OllamaBackendError.generationCancelled(generationID: generationID))
            }
        }
        return cancelResult
    }

    private func nextChatBatch() -> (
        events: [ChatStreamEvent],
        providerUsageSource: ChatProviderUsageSource?,
        shouldFinishStream: Bool
    ) {
        chatEventBatchesLock.withLock {
            let events = chatEventBatches.isEmpty ? chatEvents : chatEventBatches.removeFirst()
            let source = chatProviderUsageSources.isEmpty ? nil : chatProviderUsageSources.removeFirst()
            let shouldFinishStream = chatStreamFinishBatches.isEmpty
                ? finishChatStream
                : chatStreamFinishBatches.removeFirst()
            return (events, source, shouldFinishStream)
        }
    }

    private static func deterministicEmbedding(_ text: String) -> [Double] {
        var vector = Array(repeating: 0.0, count: 32)
        for token in text.lowercased().split(whereSeparator: { !$0.isLetter && !$0.isNumber }) {
            var hash: UInt64 = 14_695_981_039_346_656_037
            for byte in token.utf8 {
                hash ^= UInt64(byte)
                hash &*= 1_099_511_628_211
            }
            vector[Int(hash % UInt64(vector.count))] += 1
        }
        if !vector.contains(where: { $0 != 0 }) { vector[0] = 1 }
        return vector
    }
}

private final class LockedBox<Value>: @unchecked Sendable {
    private let lock = NSLock()
    private var storage: Value

    init(_ value: Value) {
        storage = value
    }

    var value: Value {
        get {
            lock.withLock { storage }
        }
        set {
            lock.withLock { storage = newValue }
        }
    }

    func mutate<Result>(_ operation: (inout Value) -> Result) -> Result {
        lock.withLock {
            operation(&storage)
        }
    }
}

private enum CompactionCalibrationStoreTestError: LocalizedError, Sendable {
    case unavailable

    var errorDescription: String? {
        "Compaction calibration store unavailable"
    }
}

private final class RecordingRuntimeChatEventStore: RuntimeChatEventStore, @unchecked Sendable {
    private let lock = NSLock()
    private var storedEvents: [RuntimeChatStoredEvent] = []
    private var storedSessions: [RuntimeChatStoredSession]
    private var storedMessages: [String: [RuntimeChatStoredMessage]]
    private var recordedSessionListRequests: [RuntimeChatSessionListRequest] = []
    private var recordedTargetedSessionSummaryRequests: [RuntimeChatTargetedSessionSummaryRequest] = []
    private var recordedAllSessionListRequestCount = 0
    private var recordedMutationRequests: [RuntimeChatMutationRequest] = []
    private let onAppend: ((RuntimeChatStoredEvent) throws -> Void)?
    private let onMutation: (@Sendable () -> Void)?
    private let sourceAttributionResolution: RuntimeChatResolvedSourceAttribution?
    private var compactionCalibrationReport: RuntimeChatCompactionCalibrationReport
    private var compactionCalibrationReportFailure: (any Error)?
    private var didReadCompactionCalibrationReportOnMainThread = false

    init(
        sessions: [RuntimeChatStoredSession] = [],
        messages: [String: [RuntimeChatStoredMessage]] = [:],
        onAppend: ((RuntimeChatStoredEvent) throws -> Void)? = nil,
        onMutation: (@Sendable () -> Void)? = nil,
        sourceAttributionResolution: RuntimeChatResolvedSourceAttribution? = nil,
        compactionCalibrationReport: RuntimeChatCompactionCalibrationReport =
            RuntimeChatCompactionCalibrationReport()
    ) {
        self.storedSessions = sessions
        self.storedMessages = messages
        self.onAppend = onAppend
        self.onMutation = onMutation
        self.sourceAttributionResolution = sourceAttributionResolution
        self.compactionCalibrationReport = compactionCalibrationReport
    }

    var events: [RuntimeChatStoredEvent] {
        lock.withLock { storedEvents }
    }

    func replaceMessages(
        sessionID: String,
        with messages: [RuntimeChatStoredMessage]
    ) {
        lock.withLock {
            storedMessages[sessionID] = messages
            if let index = storedSessions.firstIndex(where: { $0.sessionID == sessionID }) {
                storedSessions[index].messageCount = messages.count
            }
        }
    }

    func replaceSessionModel(sessionID: String, with model: String) {
        lock.withLock {
            guard let index = storedSessions.firstIndex(where: { $0.sessionID == sessionID }) else {
                return
            }
            storedSessions[index].model = model
        }
    }

    var mutationRequests: [RuntimeChatMutationRequest] {
        lock.withLock { recordedMutationRequests }
    }

    var sessionListRequests: [RuntimeChatSessionListRequest] {
        lock.withLock { recordedSessionListRequests }
    }

    var targetedSessionSummaryRequests: [RuntimeChatTargetedSessionSummaryRequest] {
        lock.withLock { recordedTargetedSessionSummaryRequests }
    }

    var allSessionListRequestCount: Int {
        lock.withLock { recordedAllSessionListRequestCount }
    }

    var compactionCalibrationReportReadWasOnMainThread: Bool {
        lock.withLock { didReadCompactionCalibrationReportOnMainThread }
    }

    func setCompactionCalibrationReportFailure(_ error: (any Error)?) {
        lock.withLock {
            compactionCalibrationReportFailure = error
        }
    }

    func append(_ event: RuntimeChatStoredEvent) throws {
        try onAppend?(event)
        lock.withLock {
            storedEvents.append(event)
            if event.kind == .title,
               let title = event.title,
               let index = storedSessions.firstIndex(where: { $0.sessionID == event.sessionID }) {
                storedSessions[index].title = title
                storedSessions[index].titleUpdatedAt = event.timestamp
                storedSessions[index].titleRevision += 1
            }
        }
    }

    func chatCompactionCalibrationReport() throws -> RuntimeChatCompactionCalibrationReport {
        try lock.withLock {
            didReadCompactionCalibrationReportOnMainThread = Thread.isMainThread
            if let compactionCalibrationReportFailure {
                throw compactionCalibrationReportFailure
            }
            return compactionCalibrationReport
        }
    }

    func mutateSession(
        ownerDeviceID: String?,
        sessionID: String,
        requestID: String,
        mutation: RuntimeChatSessionMutation,
        timestamp: Date
    ) throws -> RuntimeChatSessionMutationResult {
        onMutation?()
        lock.withLock {
            recordedMutationRequests.append(RuntimeChatMutationRequest(
                ownerDeviceID: ownerDeviceID,
                sessionID: sessionID,
                requestID: requestID,
                mutation: mutation
            ))
            storedEvents.append(RuntimeChatStoredEvent(
                timestamp: timestamp,
                kind: mutation.eventKind,
                requestID: requestID,
                sessionID: sessionID,
                model: storedSessions.first { $0.sessionID == sessionID }?.model ?? "",
                ownerDeviceID: ownerDeviceID
            ))
        }
        return RuntimeChatSessionMutationResult(sessionID: sessionID, mutation: mutation, timestamp: timestamp)
    }

    func listSessions(ownerDeviceID: String?, limit: Int, includeArchived: Bool) throws -> [RuntimeChatStoredSession] {
        lock.withLock {
            recordedSessionListRequests.append(RuntimeChatSessionListRequest(
                ownerDeviceID: ownerDeviceID,
                limit: limit,
                includeArchived: includeArchived
            ))
            return Array(storedSessions.prefix(limit))
        }
    }

    func listSessionSummaries(
        ownerDeviceID: String?,
        sessionIDs: [String],
        includeArchived: Bool
    ) throws -> [RuntimeChatStoredSession] {
        let validatedSessionIDs = try validatedTargetedSessionSummaryIDs(sessionIDs)
        let requestedSessionIDs = Set(validatedSessionIDs)
        return lock.withLock {
            recordedTargetedSessionSummaryRequests.append(RuntimeChatTargetedSessionSummaryRequest(
                ownerDeviceID: ownerDeviceID,
                sessionIDs: validatedSessionIDs,
                includeArchived: includeArchived
            ))
            return storedSessions
                .filter { session in
                    guard requestedSessionIDs.contains(session.sessionID) else { return false }
                    return session.status == "active" || (includeArchived && session.status == "archived")
                }
                .sorted { lhs, rhs in
                    if lhs.lastActivityAt != rhs.lastActivityAt {
                        return lhs.lastActivityAt > rhs.lastActivityAt
                    }
                    return lhs.sessionID < rhs.sessionID
                }
        }
    }

    func listAllSessions(limit: Int, includeArchived: Bool) throws -> [RuntimeChatStoredSession] {
        lock.withLock {
            recordedAllSessionListRequestCount += 1
            return Array(storedSessions.prefix(limit))
        }
    }

    func listMessages(ownerDeviceID: String?, sessionID: String, limit: Int) throws -> [RuntimeChatStoredMessage] {
        lock.withLock { Array((storedMessages[sessionID] ?? []).suffix(limit)) }
    }

    func listAllMessages(sessionID: String, limit: Int) throws -> [RuntimeChatStoredMessage] {
        lock.withLock { Array((storedMessages[sessionID] ?? []).suffix(limit)) }
    }

    func resolveSourceAttribution(
        ownerDeviceID: String?,
        sessionID: String,
        assistantMessageID: String,
        sourceIndex: Int
    ) throws -> RuntimeChatResolvedSourceAttribution? {
        sourceAttributionResolution
    }
}

