private final class SearchHintRecordingRuntimeChatEventStore: RuntimeChatEventStore, @unchecked Sendable {
    private let lock = NSLock()
    private let sessions: [RuntimeChatStoredSession]
    private var recordedSearchRequests: [RuntimeChatSearchListRequest] = []
    private var recordedMessageRequests: [RuntimeChatMessagesListRequest] = []
    private var semanticEmbeddingCache: [RuntimeChatSemanticEmbeddingKey: [Double]] = [:]
    private var semanticEmbeddingWrites: [[RuntimeChatSemanticEmbeddingRecord]] = []
    private var semanticEmbeddingCommitAttemptCount = 0
    private var semanticCacheReadError: Error?
    private var semanticCacheWriteError: Error?
    var onBeforeSemanticEmbeddingCommit: (() -> Void)?

    init(
        sessions: [RuntimeChatStoredSession],
        semanticCacheReadError: Error? = nil,
        semanticCacheWriteError: Error? = nil
    ) {
        self.sessions = sessions
        self.semanticCacheReadError = semanticCacheReadError
        self.semanticCacheWriteError = semanticCacheWriteError
    }

    var searchRequests: [RuntimeChatSearchListRequest] {
        lock.withLock { recordedSearchRequests }
    }

    var messageRequests: [RuntimeChatMessagesListRequest] {
        lock.withLock { recordedMessageRequests }
    }

    var cachedSemanticEmbeddingCount: Int {
        lock.withLock { semanticEmbeddingCache.count }
    }

    var semanticEmbeddingWriteBatches: [[RuntimeChatSemanticEmbeddingRecord]] {
        lock.withLock { semanticEmbeddingWrites }
    }

    var semanticCommitAttempts: Int {
        lock.withLock { semanticEmbeddingCommitAttemptCount }
    }

    func replaceCachedSemanticEmbedding(sessionID: String, embedding: [Double]) {
        lock.withLock {
            guard let key = semanticEmbeddingCache.keys.first(where: { $0.sessionID == sessionID }) else {
                return
            }
            semanticEmbeddingCache[key] = embedding
        }
    }

    func append(_ event: RuntimeChatStoredEvent) throws {}

    func listSessions(ownerDeviceID: String?, limit: Int, includeArchived: Bool) throws -> [RuntimeChatStoredSession] {
        Array(sessions.prefix(limit))
    }

    func listSessionSummaries(
        ownerDeviceID: String?,
        sessionIDs: [String],
        includeArchived: Bool
    ) throws -> [RuntimeChatStoredSession] {
        let validatedSessionIDs = try validatedTargetedSessionSummaryIDs(sessionIDs)
        let requestedSessionIDs = Set(validatedSessionIDs)
        return sessions.filter { session in
            guard requestedSessionIDs.contains(session.sessionID) else { return false }
            return session.status == "active" || (includeArchived && session.status == "archived")
        }
    }

    func listSessions(
        ownerDeviceID: String?,
        limit: Int,
        includeArchived: Bool,
        query: String?,
        embeddingModelID: String?
    ) throws -> [RuntimeChatStoredSession] {
        lock.withLock {
            recordedSearchRequests.append(RuntimeChatSearchListRequest(
                ownerDeviceID: ownerDeviceID,
                limit: limit,
                includeArchived: includeArchived,
                query: query,
                embeddingModelID: embeddingModelID
            ))
        }
        return Array(sessions.prefix(limit))
    }

    func listAllSessions(limit: Int, includeArchived: Bool) throws -> [RuntimeChatStoredSession] {
        try listSessions(ownerDeviceID: nil, limit: limit, includeArchived: includeArchived)
    }

    func listMessages(ownerDeviceID: String?, sessionID: String, limit: Int) throws -> [RuntimeChatStoredMessage] {
        lock.withLock {
            recordedMessageRequests.append(RuntimeChatMessagesListRequest(
                ownerDeviceID: ownerDeviceID,
                sessionID: sessionID,
                limit: limit
            ))
        }
        return []
    }

    func listAllMessages(sessionID: String, limit: Int) throws -> [RuntimeChatStoredMessage] {
        []
    }

    func cachedSemanticEmbeddings(
        for keys: [RuntimeChatSemanticEmbeddingKey]
    ) throws -> [RuntimeChatSemanticEmbeddingRecord] {
        try lock.withLock {
            if let semanticCacheReadError { throw semanticCacheReadError }
            return keys.compactMap { key in
                semanticEmbeddingCache[key].map {
                    RuntimeChatSemanticEmbeddingRecord(key: key, embedding: $0)
                }
            }
        }
    }

    func upsertSemanticEmbeddings(
        _ records: [RuntimeChatSemanticEmbeddingRecord],
        if shouldCommit: @Sendable () -> Bool
    ) throws {
        lock.withLock { semanticEmbeddingCommitAttemptCount += 1 }
        onBeforeSemanticEmbeddingCommit?()
        guard shouldCommit() else { return }
        try lock.withLock {
            if let semanticCacheWriteError { throw semanticCacheWriteError }
            semanticEmbeddingWrites.append(records)
            for record in records {
                semanticEmbeddingCache[record.key] = record.embedding
            }
        }
    }

    func mutateSession(
        ownerDeviceID: String?,
        sessionID: String,
        requestID: String,
        mutation: RuntimeChatSessionMutation,
        timestamp: Date
    ) throws -> RuntimeChatSessionMutationResult {
        RuntimeChatSessionMutationResult(sessionID: sessionID, mutation: mutation, timestamp: timestamp)
    }
}

private func testRuntimeInspectorError(_ message: String) -> NSError {
    NSError(
        domain: "AetherLinkTests",
        code: 100,
        userInfo: [NSLocalizedDescriptionKey: message]
    )
}

private func temporaryRuntimeChatJSONLURL() -> URL {
    FileManager.default.temporaryDirectory
        .appendingPathComponent(UUID().uuidString, isDirectory: true)
        .appendingPathComponent("runtime-chat-events.jsonl")
}

private func executeResearchNotebookSQL(_ databaseURL: URL, _ sql: String) throws {
    var database: OpaquePointer?
    guard sqlite3_open_v2(databaseURL.path, &database, SQLITE_OPEN_READWRITE, nil) == SQLITE_OK,
          let database else {
        throw testRuntimeInspectorError("Could not open research notebook test database")
    }
    defer { sqlite3_close(database) }
    guard sqlite3_exec(database, sql, nil, nil, nil) == SQLITE_OK else {
        throw testRuntimeInspectorError("Could not mutate research notebook test database")
    }
}

private func chatSessionObjects(from envelope: ProtocolEnvelope) throws -> [[String: JSONValue]] {
    guard case .array(let sessions)? = envelope.payload["sessions"] else {
        throw testRuntimeInspectorError("Expected chat sessions array")
    }
    return try sessions.map { value in
        guard case .object(let object) = value else {
            throw testRuntimeInspectorError("Expected chat session object")
        }
        return object
    }
}

private extension JSONValue {
    var objectValue: [String: JSONValue]? {
        guard case .object(let object) = self else { return nil }
        return object
    }

    var stringValue: String? {
        guard case .string(let string) = self else { return nil }
        return string
    }
}

private final class TestMonotonicClock: @unchecked Sendable {
    private let lock = NSLock()
    private var storedNow: TimeInterval

    init(now: TimeInterval) {
        storedNow = now
    }

    var now: TimeInterval {
        get { lock.withLock { storedNow } }
        set { lock.withLock { storedNow = newValue } }
    }
}

private extension RuntimeChatSessionMutation {
    var eventKind: RuntimeChatStoredEventKind {
        switch self {
        case .archive:
            return .archived
        case .restore:
            return .restored
        case .delete:
            return .deleted
        }
    }
}

private extension ChatMessage {
    var isConversationTurnForTests: Bool {
        let normalizedRole = role.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        return normalizedRole == "user" || normalizedRole == "assistant"
    }
}

private final class FailingModelPullTerminalPersistence:
    RuntimeModelPullBrokerPersistence,
    @unchecked Sendable
{
    private let store: SQLiteRuntimeModelPullApprovalStore

    init(store: SQLiteRuntimeModelPullApprovalStore) {
        self.store = store
    }

    func createPending(
        operationID: String,
        requestBindingDigest: String,
        provider: ModelProvider,
        actionID: String,
        policyRevision: String,
        requestedAt: Date,
        expiresAt: Date
    ) throws {
        try store.createPending(
            operationID: operationID,
            requestBindingDigest: requestBindingDigest,
            provider: provider,
            actionID: actionID,
            policyRevision: policyRevision,
            requestedAt: requestedAt,
            expiresAt: expiresAt
        )
    }

    func reserveDispatchBeforeProvider(
        operationID: String,
        requestBindingDigest: String,
        at: Date
    ) throws -> RuntimeModelPullReservationPersistenceResult {
        try store.reserveDispatchBeforeProvider(
            operationID: operationID,
            requestBindingDigest: requestBindingDigest,
            at: at
        )
    }

    func recordTerminal(
        operationID: String,
        event: RuntimeModelPullPersistenceEventKind,
        at: Date
    ) throws -> RuntimeModelPullTerminalPersistenceResult {
        if event == .dispatchSucceeded {
            throw ModelPullTerminalPersistenceFailure.injected
        }
        return try store.recordTerminal(operationID: operationID, event: event, at: at)
    }

    func recoverUnfinishedApprovals(at: Date) throws {
        try store.recoverUnfinishedApprovals(at: at)
    }

    func recentAuditEvents(limit: Int) throws -> [RuntimeModelPullAuditSummary] {
        try store.recentAuditEvents(limit: limit)
    }
}

private enum ModelPullTerminalPersistenceFailure: Error {
    case injected
}

private final class RecordingSink: RuntimeMessageSink, @unchecked Sendable {
    let connectionID = UUID()
    private let lock = NSLock()
    private let transportLock = NSLock()
    private var transportBinding: String?
    private var nextTransportBindingReadCheckpoint: (@Sendable () -> Void)?
    private var nextTransportTransactionCheckpoint: (@Sendable () -> Void)?
    private var messages: [ProtocolEnvelope] = []

    init(transportBinding: String? = nil) {
        self.transportBinding = transportBinding
    }

    var transportSecurityContext: TransportSecurityContext? {
        let (binding, checkpoint) = transportLock.withLock {
            let checkpoint = nextTransportBindingReadCheckpoint
            nextTransportBindingReadCheckpoint = nil
            return (transportBinding, checkpoint)
        }
        checkpoint?()
        return binding.map { TransportSecurityContext(bindingID: $0) }
    }

    func setTransportBinding(
        _ transportBinding: String?,
        beforeLock: (@Sendable () -> Void)? = nil
    ) {
        beforeLock?()
        transportLock.withLock {
            self.transportBinding = transportBinding
        }
    }

    func withTransportSecurityContextTransaction<Result>(
        _ operation: (TransportSecurityContext?) throws -> Result
    ) rethrows -> Result {
        try transportLock.withLock {
            let checkpoint = nextTransportTransactionCheckpoint
            nextTransportTransactionCheckpoint = nil
            checkpoint?()
            return try operation(
                transportBinding.map { TransportSecurityContext(bindingID: $0) }
            )
        }
    }

    func setNextTransportBindingReadCheckpoint(
        _ checkpoint: @escaping @Sendable () -> Void
    ) {
        transportLock.withLock {
            precondition(nextTransportBindingReadCheckpoint == nil)
            nextTransportBindingReadCheckpoint = checkpoint
        }
    }

    func setNextTransportTransactionCheckpoint(
        _ checkpoint: @escaping @Sendable () -> Void
    ) {
        transportLock.withLock {
            precondition(nextTransportTransactionCheckpoint == nil)
            nextTransportTransactionCheckpoint = checkpoint
        }
    }

    func tryAcquireTransportTransactionLock() -> Bool {
        guard transportLock.try() else { return false }
        transportLock.unlock()
        return true
    }

    func send(_ envelope: ProtocolEnvelope) {
        lock.withLock {
            messages.append(envelope)
        }
    }

    func close() {}

    func waitForMessages(count: Int, timeout: TimeInterval = 1.0) async throws -> [ProtocolEnvelope] {
        let deadline = Date().addingTimeInterval(timeout)
        while Date() < deadline {
            let snapshot = lock.withLock { messages }
            if snapshot.count >= count {
                return snapshot
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        return lock.withLock { messages }
    }
}

private final class DeferredPublicationSink: RuntimeMessageSink, @unchecked Sendable {
    let connectionID = UUID()
    let publicationEntered = DispatchSemaphore(value: 0)
    private let lock = NSLock()
    private var messages: [ProtocolEnvelope] = []
    private var publicationCompletion: (@Sendable (Bool) -> Void)?

    func withTransportSecurityContextTransaction<Result>(
        _ operation: (TransportSecurityContext?) throws -> Result
    ) rethrows -> Result {
        try operation(nil)
    }

    func send(_ envelope: ProtocolEnvelope) {
        lock.withLock { messages.append(envelope) }
    }

    func send(
        _ envelope: ProtocolEnvelope,
        completion: @escaping @Sendable (Bool) -> Void
    ) {
        lock.withLock {
            messages.append(envelope)
            precondition(publicationCompletion == nil)
            publicationCompletion = completion
        }
        publicationEntered.signal()
    }

    func complete(succeeded: Bool) {
        let completion = lock.withLock { () -> (@Sendable (Bool) -> Void)? in
            let completion = publicationCompletion
            publicationCompletion = nil
            return completion
        }
        completion?(succeeded)
    }

    func close() {
        complete(succeeded: false)
    }

    func waitForMessages(count: Int, timeout: TimeInterval = 1) async throws -> [ProtocolEnvelope] {
        let deadline = Date().addingTimeInterval(timeout)
        while Date() < deadline {
            let snapshot = lock.withLock { messages }
            if snapshot.count >= count { return snapshot }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        return lock.withLock { messages }
    }
}

private final class BlockingPublicationSink: RuntimeMessageSink, @unchecked Sendable {
    let connectionID = UUID()
    let publicationEntered = DispatchSemaphore(value: 0)
    let releasePublication = DispatchSemaphore(value: 0)
    private let lock = NSLock()
    private var messages: [ProtocolEnvelope] = []

    func withTransportSecurityContextTransaction<Result>(
        _ operation: (TransportSecurityContext?) throws -> Result
    ) rethrows -> Result {
        try operation(nil)
    }

    func send(_ envelope: ProtocolEnvelope) {
        lock.withLock { messages.append(envelope) }
    }

    func send(
        _ envelope: ProtocolEnvelope,
        completion: @escaping @Sendable (Bool) -> Void
    ) {
        lock.withLock { messages.append(envelope) }
        publicationEntered.signal()
        releasePublication.wait()
        completion(true)
    }

    func close() {
        releasePublication.signal()
    }

    func waitForMessages(count: Int, timeout: TimeInterval = 1) async throws -> [ProtocolEnvelope] {
        let deadline = Date().addingTimeInterval(timeout)
        while Date() < deadline {
            let snapshot = lock.withLock { messages }
            if snapshot.count >= count { return snapshot }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        return lock.withLock { messages }
    }
}

private final class ChangingTransportBindingSink: RuntimeMessageSink, @unchecked Sendable {
    let connectionID = UUID()

    private let lock = NSLock()
    private let initialBinding: String
    private let changedBinding: String
    private var bindingReadCount = 0
    private var messages: [ProtocolEnvelope] = []

    init(initialBinding: String, changedBinding: String) {
        self.initialBinding = initialBinding
        self.changedBinding = changedBinding
    }

    var transportSecurityContext: TransportSecurityContext? {
        lock.withLock {
            bindingReadCount += 1
            let binding = bindingReadCount == 1 ? initialBinding : changedBinding
            return TransportSecurityContext(bindingID: binding)
        }
    }

    func withTransportSecurityContextTransaction<Result>(
        _ operation: (TransportSecurityContext?) throws -> Result
    ) rethrows -> Result {
        let context = transportSecurityContext
        return try operation(context)
    }

    func send(_ envelope: ProtocolEnvelope) {
        lock.withLock {
            messages.append(envelope)
        }
    }

    func close() {}

    func waitForMessages(count: Int, timeout: TimeInterval = 2) async throws -> [ProtocolEnvelope] {
        let deadline = Date().addingTimeInterval(timeout)
        while Date() < deadline {
            let snapshot = lock.withLock { messages }
            if snapshot.count >= count {
                return snapshot
            }
            try await Task.sleep(nanoseconds: 10_000_000)
        }
        return lock.withLock { messages }
    }
}

private final class FakeRuntimeTransport: RuntimeTransport {
    private let statusAfterStart: PeerServerStatus?
    private(set) var status = PeerServerStatus.stopped
    private(set) var startedPort: UInt16?
    private(set) var didStop = false
    private(set) var onMessage: LocalPeerMessageHandler?

    init(statusAfterStart: PeerServerStatus? = nil) {
        self.statusAfterStart = statusAfterStart
    }

    func start(port: UInt16, onMessage: @escaping LocalPeerMessageHandler) {
        startedPort = port
        self.onMessage = onMessage
        didStop = false
        status = statusAfterStart ?? .listening(port: port)
    }

    func stop() {
        didStop = true
        onMessage = nil
        status = .stopped
    }
}

private final class FakeRuntimeAdvertiser: RuntimeAdvertiser {
    private(set) var startedPort: Int32?
    private(set) var startedMetadata: RuntimeAdvertisementMetadata?
    private(set) var didStop = false

    func start(port: Int32, metadata: RuntimeAdvertisementMetadata) {
        startedPort = port
        startedMetadata = metadata
        didStop = false
    }

    func stop() {
        didStop = true
    }
}

private final class FakeRelayPeerClient: RelayPeerTransport, @unchecked Sendable {
    private(set) var startedConfiguration: RelayPeerConfiguration?
    private(set) var didStop = false
    private let onStart: (() -> Void)?
    private var statusHandler: (@Sendable (RelayPeerStatus) -> Void)?

    init(onStart: (() -> Void)? = nil) {
        self.onStart = onStart
    }

    func start(
        configuration: RelayPeerConfiguration,
        onStatusChange: (@Sendable (RelayPeerStatus) -> Void)?,
        onMessage: @escaping LocalPeerMessageHandler
    ) {
        onStart?()
        startedConfiguration = configuration
        statusHandler = onStatusChange
        didStop = false
    }

    func stop() {
        didStop = true
        statusHandler?(.stopped)
        statusHandler = nil
    }

    func emit(_ status: RelayPeerStatus) {
        statusHandler?(status)
    }
}

private extension NSLock {
    func withLock<T>(_ body: () throws -> T) rethrows -> T {
        lock()
        defer { unlock() }
        return try body()
    }
}
